// Base class
class Animal {
    protected String name;
    protected int age;

    public Animal(String name, int age) {
        this.name = name;
        this.age = age;
    }

    public void eat() {
        System.out.println(name + " is eating.");
    }

    public void makeSound() {
        System.out.println(name + " makes a generic sound.");
    }

    @Override
    public String toString() {
        return name + " (age: " + age + ")";
    }
}

// Subclass - inherits from Animal
class Dog extends Animal {
    private String breed;

    public Dog(String name, int age, String breed) {
        super(name, age); // Call parent constructor
        this.breed = breed;
    }

    @Override
    public void makeSound() {
        System.out.println(name + " barks: Woof! Woof!");
    }

    public void fetch() {
        System.out.println(name + " is fetching the ball!");
    }

    @Override
    public String toString() {
        return name + " (" + breed + ", age: " + age + ")";
    }
}

// Another subclass
class Cat extends Animal {
    private boolean isIndoor;

    public Cat(String name, int age, boolean isIndoor) {
        super(name, age);
        this.isIndoor = isIndoor;
    }

    @Override
    public void makeSound() {
        System.out.println(name + " meows: Meow! Meow!");
    }
}

public class InheritanceDemo {
    public static void main(String[] args) {
        Animal animal = new Animal("Generic Animal", 5);
        Dog dog = new Dog("Buddy", 3, "Golden Retriever");
        Cat cat = new Cat("Whiskers", 2, true);

        // Inherited method
        dog.eat();
        cat.eat();

        // Overridden methods (polymorphism)
        animal.makeSound();
        dog.makeSound();
        cat.makeSound();

        // Dog-specific method
        dog.fetch();

        // Polymorphic reference
        Animal polyRef = new Dog("Rex", 4, "Labrador");
        polyRef.makeSound(); // Calls Dog's version at runtime

        System.out.println("\nAll animals:");
        System.out.println(animal);
        System.out.println(dog);
        System.out.println(cat);
    }
}

// Interface defining a contract
interface Payable {
    double calculatePay();
    default String getPaymentMethod() {
        return "Direct Deposit";
    }
}

interface Reportable {
    String generateReport();
}

// Abstract class with shared implementation
abstract class Employee implements Payable, Reportable {
    protected String name;
    protected String id;
    protected double baseSalary;

    public Employee(String name, String id, double baseSalary) {
        this.name = name;
        this.id = id;
        this.baseSalary = baseSalary;
    }

    // Concrete method shared by all employees
    public void displayInfo() {
        System.out.println("ID: " + id + " | Name: " + name + " | Base Salary: $" + baseSalary);
    }

    // Abstract method - each employee type calculates differently
    public abstract String getRole();

    @Override
    public String generateReport() {
        return "Employee Report: " + name + " [" + getRole() + "] - Pay: $" + String.format("%.2f", calculatePay());
    }
}

// Concrete class
class FullTimeEmployee extends Employee {
    private double bonus;

    public FullTimeEmployee(String name, String id, double baseSalary, double bonus) {
        super(name, id, baseSalary);
        this.bonus = bonus;
    }

    @Override
    public double calculatePay() {
        return baseSalary + bonus;
    }

    @Override
    public String getRole() {
        return "Full-Time";
    }
}

// Another concrete class
class ContractEmployee extends Employee {
    private int hoursWorked;
    private double hourlyRate;

    public ContractEmployee(String name, String id, double hourlyRate, int hoursWorked) {
        super(name, id, 0);
        this.hourlyRate = hourlyRate;
        this.hoursWorked = hoursWorked;
    }

    @Override
    public double calculatePay() {
        return hourlyRate * hoursWorked;
    }

    @Override
    public String getRole() {
        return "Contractor";
    }

    @Override
    public String getPaymentMethod() {
        return "Invoice Payment";
    }
}

public class AbstractionDemo {
    public static void main(String[] args) {
        Employee[] employees = {
            new FullTimeEmployee("Alice", "FT001", 5000, 1200),
            new FullTimeEmployee("Bob", "FT002", 6000, 1500),
            new ContractEmployee("Charlie", "CT001", 75, 160),
            new ContractEmployee("Diana", "CT002", 100, 120)
        };

        System.out.println("=== Employee Payroll System ===");
        double totalPayroll = 0;

        for (Employee emp : employees) {
            emp.displayInfo();
            System.out.println("  Role: " + emp.getRole());
            System.out.println("  Pay: $" + String.format("%.2f", emp.calculatePay()));
            System.out.println("  Payment Method: " + emp.getPaymentMethod());
            System.out.println("  " + emp.generateReport());
            System.out.println();
            totalPayroll += emp.calculatePay();
        }

        System.out.println("Total Payroll: $" + String.format("%.2f", totalPayroll));
    }
}

import java.util.ArrayList;
import java.util.List;

// Interface for discountable items
interface Discountable {
    double applyDiscount(double discountPercent);
}

// Abstract product class
abstract class Product implements Discountable {
    private String productId;
    private String name;
    private double price;

    public Product(String productId, String name, double price) {
        this.productId = productId;
        this.name = name;
        this.price = price;
    }

    public String getProductId() { return productId; }
    public String getName() { return name; }
    public double getPrice() { return price; }
    protected void setPrice(double price) { this.price = price; }

    public abstract String getCategory();

    @Override
    public double applyDiscount(double discountPercent) {
        return price * (1 - discountPercent / 100);
    }

    @Override
    public String toString() {
        return String.format("[%s] %s - $%.2f (%s)", productId, name, price, getCategory());
    }
}

// Concrete product types
class Electronics extends Product {
    private int warrantyMonths;

    public Electronics(String id, String name, double price, int warrantyMonths) {
        super(id, name, price);
        this.warrantyMonths = warrantyMonths;
    }

    @Override
    public String getCategory() { return "Electronics"; }

    @Override
    public String toString() {
        return super.toString() + " | Warranty: " + warrantyMonths + " months";
    }
}

class Clothing extends Product {
    private String size;

    public Clothing(String id, String name, double price, String size) {
        super(id, name, price);
        this.size = size;
    }

    @Override
    public String getCategory() { return "Clothing"; }

    @Override
    public double applyDiscount(double discountPercent) {
        // Clothing gets an extra 5% off during sales
        return getPrice() * (1 - (discountPercent + 5) / 100);
    }
}

// Shopping Cart using composition (HAS-A relationship)
class ShoppingCart {
    private List<Product> items;

    public ShoppingCart() {
        this.items = new ArrayList<>();
    }

    public void addItem(Product product) {
        items.add(product);
        System.out.println("Added: " + product.getName());
    }

    public double calculateTotal() {
        double total = 0;
        for (Product item : items) {
            total += item.getPrice();
        }
        return total;
    }

    public double calculateDiscountedTotal(double discountPercent) {
        double total = 0;
        for (Product item : items) {
            total += item.applyDiscount(discountPercent); // Polymorphism!
        }
        return total;
    }

    public void displayCart() {
        System.out.println("\n=== Shopping Cart ===");
        for (Product item : items) {
            System.out.println("  " + item);
        }
        System.out.printf("  Total: $%.2f%n", calculateTotal());
    }
}

public class ShoppingSystem {
    public static void main(String[] args) {
        // Create products (polymorphic creation)
        Product laptop = new Electronics("E001", "Laptop Pro", 1299.99, 24);
        Product phone = new Electronics("E002", "SmartPhone X", 799.99, 12);
        Product shirt = new Clothing("C001", "Cotton Shirt", 49.99, "L");
        Product jacket = new Clothing("C002", "Winter Jacket", 149.99, "M");

        // Create cart and add items
        ShoppingCart cart = new ShoppingCart();
        cart.addItem(laptop);
        cart.addItem(phone);
        cart.addItem(shirt);
        cart.addItem(jacket);

        // Display cart
        cart.displayCart();

        // Apply 10% discount — polymorphism in action
        double discounted = cart.calculateDiscountedTotal(10);
        System.out.printf("%nAfter 10%% discount: $%.2f%n", discounted);
        System.out.printf("You save: $%.2f%n", cart.calculateTotal() - discounted);
    }
}

