import java.util.ArrayList;
import java.util.List;

interface Insurable {
    double getInsuranceCost();
}

abstract class Vehicle implements Insurable {
    private String id;
    private String brand;
    private double dailyRate;

    public Vehicle(String id, String brand, double dailyRate) {
        this.id = id;
        this.brand = brand;
        this.dailyRate = dailyRate;
    }

    public String getId() { return id; }
    public String getBrand() { return brand; }
    public double getDailyRate() { return dailyRate; }

    public abstract double calculateRentalCost(int days);
    public abstract String getRentalBreakdown(int days);
}

class Car extends Vehicle {
    private double kmPerDay;
    private static final double KM_SURCHARGE_RATE = 0.25;
    private static final int FREE_KM_LIMIT = 200;

    public Car(String id, String brand, double dailyRate, double kmPerDay) {
        super(id, brand, dailyRate);
        this.kmPerDay = kmPerDay;
    }

    @Override
    public double calculateRentalCost(int days) {
        double base = getDailyRate() * days;
        double surcharge = 0;
        if (kmPerDay > FREE_KM_LIMIT) {
            surcharge = (kmPerDay - FREE_KM_LIMIT) * KM_SURCHARGE_RATE * days;
        }
        return base + surcharge;
    }

    @Override
    public String getRentalBreakdown(int days) {
        double base = getDailyRate() * days;
        double surcharge = (kmPerDay > FREE_KM_LIMIT) ? (kmPerDay - FREE_KM_LIMIT) * KM_SURCHARGE_RATE * days : 0;
        return String.format("Car Rental (%d days): $%.2f (base: $%.2f + km surcharge: $%.2f)", days, base + surcharge, base, surcharge);
    }

    @Override
    public double getInsuranceCost() { return 15.0; }
}

class Truck extends Vehicle {
    private String weightCategory;

    public Truck(String id, String brand, double dailyRate, String weightCategory) {
        super(id, brand, dailyRate);
        this.weightCategory = weightCategory;
    }

    @Override
    public double calculateRentalCost(int days) {
        double base = getDailyRate() * days;
        double surcharge = weightCategory.equalsIgnoreCase("Heavy") ? base * 0.5 : base * 0.2;
        return base + surcharge;
    }

    @Override
    public String getRentalBreakdown(int days) {
        double base = getDailyRate() * days;
        double surcharge = weightCategory.equalsIgnoreCase("Heavy") ? base * 0.5 : base * 0.2;
        return String.format("Truck Rental (%d days): $%.2f (base: $%.2f + %s surcharge: $%.2f)", days, base + surcharge, base, weightCategory.toLowerCase(), surcharge);
    }

    @Override
    public double getInsuranceCost() { return 30.0; }
}

class Motorcycle extends Vehicle {
    private static final int LOYALTY_THRESHOLD = 7;
    private static final double DISCOUNT_RATE = 0.15;

    public Motorcycle(String id, String brand, double dailyRate) {
        super(id, brand, dailyRate);
    }

    @Override
    public double calculateRentalCost(int days) {
        double base = getDailyRate() * days;
        if (days > LOYALTY_THRESHOLD) {
            return base * (1 - DISCOUNT_RATE);
        }
        return base;
    }

    @Override
    public String getRentalBreakdown(int days) {
        double base = getDailyRate() * days;
        double discount = days > LOYALTY_THRESHOLD ? base * DISCOUNT_RATE : 0;
        return String.format("Motorcycle Rental (%d days): $%.2f (base: $%.2f - loyalty discount: $%.2f)", days, base - discount, base, discount);
    }

    @Override
    public double getInsuranceCost() { return 10.0; }
}

public class VehicleRentalSystem {
    public static void main(String[] args) {
        Car car = new Car("C001", "Toyota", 50.0, 300);
        Truck truck = new Truck("T001", "Ford", 120.0, "Heavy");
        Motorcycle moto = new Motorcycle("M001", "Honda", 50.0);

        int[] rentalDays = {5, 3, 10};
        Vehicle[] fleet = {car, truck, moto};

        double totalCost = 0;
        for (int i = 0; i < fleet.length; i++) {
            System.out.println(fleet[i].getRentalBreakdown(rentalDays[i]));
            totalCost += fleet[i].calculateRentalCost(rentalDays[i]);
        }
        System.out.printf("Total Fleet Cost: $%.2f%n", totalCost);
    }
}

interface Drawable {
    void draw();
    void resize(double factor);
}

abstract class Shape implements Drawable {
    private String color;
    private boolean filled;

    public Shape(String color, boolean filled) {
        this.color = color;
        this.filled = filled;
    }

    public String getColor() { return color; }
    public boolean isFilled() { return filled; }

    public void setColor(String color) {
        if (color != null && !color.isEmpty()) this.color = color;
    }

    public abstract double area();

    protected String getDescription() {
        return "[" + color + ", " + (filled ? "filled" : "not filled") + "]";
    }
}

class Circle extends Shape {
    private double radius;

    public Circle(String color, double radius) {
        super(color, true);
        this.radius = radius > 0 ? radius : 1.0;
    }

    @Override
    public double area() { return Math.PI * radius * radius; }

    @Override
    public void draw() {
        System.out.printf("Drawing Circle %s - Radius: %.1f, Area: %.2f%n", getDescription(), radius, area());
    }

    @Override
    public void resize(double factor) {
        if (factor > 0) radius *= factor;
    }
}

class Rectangle extends Shape {
    private double width, height;

    public Rectangle(String color, double width, double height) {
        super(color, true);
        this.width = width > 0 ? width : 1.0;
        this.height = height > 0 ? height : 1.0;
    }

    @Override
    public double area() { return width * height; }

    @Override
    public void draw() {
        System.out.printf("Drawing Rectangle %s - %.1fx%.1f, Area: %.2f%n", getDescription(), width, height, area());
    }

    @Override
    public void resize(double factor) {
        if (factor > 0) { width *= factor; height *= factor; }
    }
}

class Triangle extends Shape {
    private double a, b, c;

    public Triangle(String color, double a, double b, double c) {
        super(color, true);
        this.a = a; this.b = b; this.c = c;
    }

    @Override
    public double area() {
        double s = (a + b + c) / 2;
        return Math.sqrt(s * (s - a) * (s - b) * (s - c));
    }

    @Override
    public void draw() {
        System.out.printf("Drawing Triangle %s - Sides: %.1f, %.1f, %.1f, Area: %.2f%n", getDescription(), a, b, c, area());
    }

    @Override
    public void resize(double factor) {
        if (factor > 0) { a *= factor; b *= factor; c *= factor; }
    }
}

public class ShapeDrawingApp {
    public static void main(String[] args) {
        Shape[] shapes = {
            new Circle("red", 5.0),
            new Rectangle("blue", 4.0, 6.0),
            new Triangle("green", 3.0, 4.0, 5.0)
        };

        for (Shape s : shapes) s.draw();

        System.out.println("\nAfter resizing by 2.0x:");
        for (Shape s : shapes) {
            s.resize(2.0);
            s.draw();
        }
    }
}
